// Pseudocode: dedupe then persist per tenant
async function handleEvent(ctx) {
  const {tenantId, eventId} = ctx.bindingData;
  const exists = await cosmos.read(`dedup/${tenantId}/${eventId}`);
  if (exists) return;
  await cosmos.upsert(`dedup/${tenantId}/${eventId}`, true);
  // write main event data to tenant partition
}
```

