// Example of idempotent handler scaffold
module.exports = async function(context, eventGridEvent) {
  const id = eventGridEvent.id;
  // check per-tenant dedup store
  const seen = await dedupStore.contains(`dedup:${id}`);
  if (seen) return;
  await dedupStore.add(`dedup:${id}`);
  await enqueueOutbound(eventGridEvent);
};
